class Solution:
    def diameterOfBinaryTree(self, root) -> int:
        self.best = 0                # 最长路径的「边数」

        def depth(n):                # 返回以 n 为根的高度(结点数)
            if not n:
                return 0
            l = depth(n.left)
            r = depth(n.right)
            self.best = max(self.best, l + r)   # 经过 n 的路径边数 = 左高 + 右高
            return 1 + max(l, r)     # 向上返回:取较高一侧 + 1

        depth(root)
        return self.best
